INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/06/30 12:00:00", 2, "クローチェ", 1, 1.47, "2023/09/22 14:59:59", "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 0.0, 1, 10001, 126401, 1, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/06/30 12:00:00", 1, "クローチェ", 2, 2.15, "2023/09/22 14:59:59", "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 0.0, 2, 10002, 126401, 1, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/06/30 12:00:00", 2, "ライラエル", 2, 0.0, "2023/09/22 14:59:59", "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 0.0, 1, 10003, 126501, 1, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/06/30 12:00:00", 1, "ライラエル", 1, 0.0, "2023/09/22 14:59:59", "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 0.0, 2, 10004, 126501, 1, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/09/15 15:00:00", 2, "リンド", 2, 0.0, "2023/12/22 14:59:59", "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 0.0, 1, 10005, 127702, 2, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/09/15 15:00:00", 2, "リンド", 2, 0.0, "2023/12/22 14:59:59", "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 0.0, 2, 10006, 127702, 2, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/09/15 15:00:00", 1, "ヴルム", 1, 0.0, "2023/12/22 14:59:59", "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 0.0, 1, 10007, 127802, 2, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/09/15 15:00:00", 1, "ヴルム", 2, 6.5, "2023/12/22 14:59:59", "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 0.0, 2, 10008, 127802, 2, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/12/15 15:00:00", 1, "アネモネ", 2, 0.0, "2024/03/22 14:59:59", "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 0.0, 1, 10009, 129602, 3, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/12/15 15:00:00", 1, "アネモネ", 2, 0.0, "2024/03/22 14:59:59", "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 0.0, 2, 10010, 129602, 3, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/12/15 15:00:00", 1, "ネフィ=ネラ", 1, 0.0, "2024/03/22 14:59:59", "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 0.0, 1, 10011, 129701, 3, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2023/12/15 15:00:00", 1, "ネフィ=ネラ", 2, 6.2, "2024/03/22 14:59:59", "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 0.0, 2, 10012, 129701, 3, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/03/15 15:00:00", 5, "カノン", 3, 3.1, "2024/06/22 14:59:59", "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 0.0, 1, 10013, 130301, 4, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/03/15 15:00:00", 2, "カノン", 3, 6.15, "2024/06/22 14:59:59", "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 0.0, 2, 10014, 130301, 4, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/03/15 15:00:00", 2, "ナーナ", 2, 0.0, "2024/06/22 14:59:59", "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 0.0, 1, 10015, 130401, 4, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/03/15 15:00:00", 1, "ナーナ", 2, 3.35, "2024/06/22 14:59:59", "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 0.0, 2, 10016, 130401, 4, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/06/15 15:00:00", 1, "ホウオウ", 1, 0.0, "2024/09/22 14:59:59", "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 0.0, 1, 10017, 130502, 5, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/06/15 15:00:00", 1, "ホウオウ", 2, 3.18, "2024/09/22 14:59:59", "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 0.0, 2, 10018, 130502, 5, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/06/15 15:00:00", 4, "ホウオウ", 4, 0.0, "2024/09/22 14:59:59", "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 0.0, 3, 10019, 130503, 5, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/06/15 15:00:00", 2, "ネア", 1, 4.9, "2024/09/22 14:59:59", "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 0.0, 1, 10020, 123301, 5, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/06/15 15:00:00", 2, "ネア", 1, 4.8, "2024/09/22 14:59:59", "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 0.0, 2, 10021, 123301, 5, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/09/15 15:00:00", 1, "カリザ", 3, 4.922, "2024/12/22 14:59:59", "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 0.0, 1, 10022, 133301, 6, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/09/15 15:00:00", 5, "カリザ", 3, 9.638, "2024/12/22 14:59:59", "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 0.0, 2, 10023, 133301, 6, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/09/15 15:00:00", 2, "ミーア", 1, 2.88, "2024/12/22 14:59:59", "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 0.0, 1, 10024, 133401, 6, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/09/15 15:00:00", 1, "ミーア", 5, 4.818, "2024/12/22 14:59:59", "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 0.0, 2, 10025, 133401, 6, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/12/15 15:00:00", 1, "グレイス", 2, 1.78, "2025/03/22 14:59:59", "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 0.0, 1, 10026, 133002, 7, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/12/15 15:00:00", 7, "グレイス", 1, 6.15, "2025/03/22 14:59:59", "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 0.0, 2, 10027, 133002, 7, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/12/15 15:00:00", 2, "ヴァイオレット", 6, 4.28, "2025/03/22 14:59:59", "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 0.0, 1, 10028, 133102, 7, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2024/12/15 15:00:00", 1, "ヴァイオレット", 1, 0.0, "2025/03/22 14:59:59", "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 0.0, 2, 10029, 133102, 7, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/03/15 15:00:00", 1, "ルルィ", 2, 5.53, "2025/06/23 14:59:59", "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 0.0, 1, 10030, 136902, 8, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/03/15 15:00:00", 7, "ルルィ", 9, 6.05, "2025/06/23 14:59:59", "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 0.0, 2, 10031, 136902, 8, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/03/15 15:00:00", 1, "デュラン", 2, 0.0, "2025/06/23 14:59:59", "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 0.0, 1, 10032, 137001, 8, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/03/15 15:00:00", 1, "デュラン", 2, 0.0, "2025/06/23 14:59:59", "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 0.0, 2, 10033, 137001, 8, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/06/16 15:00:00", 2, "サツキ", 2, 0.0, "2025/09/23 14:59:59", "おう\n好きなもん持ってきな", 0.0, 1, 10034, 135902, 9, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/06/16 15:00:00", 6, "サツキ", 1, 4.935, "2025/09/23 14:59:59", "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 0.0, 2, 10035, 135902, 9, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/06/16 15:00:00", 5, "ユキノ", 2, 7.441, "2025/09/23 14:59:59", "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 0.0, 1, 10036, 135802, 9, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/06/16 15:00:00", 7, "ユキノ", 7, 0.0, "2025/09/23 14:59:59", "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 0.0, 2, 10037, 135802, 9, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/09/16 15:00:00", 2, "クルル", 2, 2.295, "2025/12/22 14:59:59", "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 0.0, 1, 10038, 130901, 10, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/09/16 15:00:00", 6, "クルル", 1, 6.281, "2025/12/22 14:59:59", "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 0.0, 2, 10039, 130901, 10, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/09/16 15:00:00", 1, "ヴォルガーノ", 2, 5.549, "2025/12/22 14:59:59", "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 0.0, 1, 10040, 137701, 10, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/09/16 15:00:00", 6, "ヴォルガーノ", 3, 2.64, "2025/12/22 14:59:59", "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 0.0, 2, 10041, 137701, 10, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/12/15 15:00:00", 4, "ライラエル", 7, 7.642, "2026/03/23 11:59:59", "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 0.0, 1, 10042, 132801, 11, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/12/15 15:00:00", 1, "ライラエル", 1, 0.0, "2026/03/23 11:59:59", "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 0.0, 2, 10043, 132802, 11, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/12/15 15:00:00", 1, "クローチェ", 1, 0.0, "2026/03/23 11:59:59", "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 0.0, 1, 10044, 134502, 11, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2025/12/15 15:00:00", 1, "クローチェ", 2, 3.72, "2026/03/23 11:59:59", "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 0.0, 2, 10045, 134501, 11, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/03/16 12:00:00", 1, "ネフィ＝ネラ", 2, 4.991, "2026/06/22 11:59:59", "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 0.0, 1, 10046, 138201, 12, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/03/16 12:00:00", 4, "ネフィ＝ネラ", 1, 3.877, "2026/06/22 11:59:59", "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 0.0, 2, 10047, 138201, 12, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/03/16 12:00:00", 6, "アラクネ", 4, 1.71, "2026/06/22 11:59:59", "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 0.0, 1, 10048, 136001, 12, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/03/16 12:00:00", 2, "アラクネ", 5, 5.32, "2026/06/22 11:59:59", "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 0.0, 2, 10049, 136001, 12, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/06/15 12:00:00", 4, "アネモネ", 9, 3.727, "2026/09/22 11:59:59", "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 0.0, 1, 10050, 135401, 13, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/06/15 12:00:00", 9, "アネモネ", 7, 7.213, "2026/09/22 11:59:59", "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 0.0, 2, 10051, 135401, 13, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/06/15 12:00:00", 2, "クリア", 1, 1.874, "2026/09/22 11:59:59", "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 0.0, 1, 10052, 135301, 13, 2002, -470.0);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES ("2026/06/15 12:00:00", 2, "クリア", 2, 0.0, "2026/09/22 11:59:59", "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 0.0, 2, 10053, 135301, 13, 2002, -470.0);
